 8→export const Input = forwardRef<HTMLInputElement, InputProps>(
 9→  ({ label, error, id, className = '', ...props }, ref) => {
10→    const inputId = id || label.toLowerCase().replace(/\s+/g, '-');
11→
12→    return (
13→      <div className="space-y-1">
14→        <label
15→          htmlFor={inputId}
16→          className="block text-sm font-medium text-[var(--color-text)]"
17→        >
18→          {label}
19→        </label>
20→        <input
21→          ref={ref}
22→          id={inputId}
23→          className={`block w-full rounded-lg border px-3 py-2.5 text-sm transition-colors focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)] focus:ring-offset-1 ${
24→            error
25→              ? 'border-red-500 focus:ring-red-500'
26→              : 'border-slate-300 focus:border-[var(--color-primary)]'
27→          } ${className}`}
28→          aria-invalid={!!error}
29→          aria-describedby={error ? `${inputId}-error` : undefined}
30→          {...props}
31→        />
32→        {error && (
